"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { Card, Button, Badge, Input } from "@/components/marketing/ui";
import {
  EXAMS,
  getExam,
  bandFor,
  type Exam,
  type Question,
} from "@/lib/marketing-tests/exams";

type Phase = "picker" | "running" | "results" | "history";

interface AnswerRecord {
  questionId: string;
  selected: number;
  correct: number;
  skill: string;
  difficulty: number;

// Marketing exams data + scoring helpers.
// Pure TypeScript — no React/next imports, no DOM access.
// Compiles under `tsc --strict` with noUnusedLocals / noUnusedParameters.

export type QuestionType = "mcq" | "truefalse" | "multiselect" | "numeric";
export type Difficulty = 1 | 2 | 3;

export interface MCQQuestion {
  id: string;
  type: "mcq";
  prompt: string;
  options: string[];
  correct: number;
  explanation: string;
  skill: string;
  difficulty: Difficulty;
}

export interface TrueFalseQuestion {
  id: string;

"use client";

import React from "react";
import { Card, Button, Badge } from "@/components/marketing/ui";
import {
  certificateId,
  getExam,
  type SkillBand,
} from "@/lib/marketing-tests/exams";

export interface ExamResult {
  attemptId: string;
  examId: string;
  examTitle: string;
  domain: string;
  score: number;
  total: number;
  correctCount: number;
  percentage: number;
  passed: boolean;

"use client";

import React from "react";

export function Card({ className = "", children, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div className={`bg-white rounded-lg border border-gray-200 shadow-sm ${className}`} {...props}>
      {children}
    </div>
  );
}

export function Button({ className = "", children, variant = "default", ...props }: React.ButtonHTMLAttributes<HTMLButtonElement> & { variant?: "default" | "outline" | "ghost" | "destructive" | "secondary" }) {
  const variants: Record<string, string> = {
    default: "bg-indigo-600 text-white hover:bg-indigo-700",
    outline: "border border-gray-300 bg-transparent hover:bg-gray-50",
    ghost: "hover:bg-gray-100",
    destructive: "bg-red-600 text-white hover:bg-red-700",
    secondary: "bg-gray-100 text-gray-900 hover:bg-gray-200",
  };

