"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { Card, Button, Badge, Input } from "@/components/marketing/ui";
import {
  EXAMS,
  getExam,
  bandFor,
  DIFFICULTY_WEIGHT,
  examMaxWeight,
  isMultiSelect,
  isNumeric,
  type Exam,
  type Question,
  type QuestionType,
  type Difficulty,
} from "@/lib/marketing-tests/exams";
import { ExamCertificate } from "@/components/marketing/ExamCertificate";
import type { ExamResult } from "@/components/marketing/ExamCertificate";
import { RecruiterCompare } from "@/components/marketing/RecruiterCompare";

type Phase = "picker" | "running" | "results" | "history" | "compare";

interface AnswerRecord {
  questionId: string;
  type: QuestionType;
  selected: number | number[];
  correct: number | number[];
  skill: string;
  difficulty: Difficulty;
  isCorrect: boolean;
  earnedWeight: number;
  maxWeight: number;
}

interface Candidate {
  name: string;
  email: string;
}

const HISTORY_KEY = "marketing-hub:exam-history";
const CANDIDATE_KEY = "marketing-hub:exam-candidate";

function loadHistory(): ExamResult[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(HISTORY_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as ExamResult[];
    if (!Array.isArray(parsed)) return [];
    return parsed;
  } catch {
    return [];
  }
}

function saveHistory(list: ExamResult[]) {
  try {
    localStorage.setItem(HISTORY_KEY, JSON.stringify(list.slice(0, 100)));
  } catch {
    // ignore quota / private mode
  }
}

function loadCandidate(): Candidate {
  if (typeof window === "undefined") return { name: "", email: "" };
  try {
    const raw = localStorage.getItem(CANDIDATE_KEY);
    if (!raw) return { name: "", email: "" };
    const parsed = JSON.parse(raw) as Partial<Candidate>;
    return { name: parsed.name ?? "", email: parsed.email ?? "" };
  } catch {
    return { name: "", email: "" };
  }
}

function saveCandidate(c: Candidate) {
  try {
    localStorage.setItem(CANDIDATE_KEY, JSON.stringify(c));
  } catch {
    // ignore
  }
}

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j]!, a[i]!];
  }
  return a;
}

function gradeColor(percentage: number): string {
  if (percentage >= 85) return "bg-green-100 text-green-800 border-green-200";
  if (percentage >= 70) return "bg-blue-100 text-blue-800 border-blue-200";
  if (percentage >= 50) return "bg-amber-100 text-amber-800 border-amber-200";
  return "bg-red-100 text-red-800 border-red-200";
}

function difficultyLabel(d: Difficulty): string {
  return d === 1 ? "Easy" : d === 2 ? "Medium" : "Hard";
}

function fmtDuration(totalSeconds: number): string {
  const m = Math.floor(totalSeconds / 60);
  const s = totalSeconds % 60;
  return `${m}m ${s.toString().padStart(2, "0")}s`;
}

function fmtCountdown(secondsLeft: number): string {
  if (secondsLeft <= 0) return "0:00";
  const m = Math.floor(secondsLeft / 60);
  const s = secondsLeft % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

export function MarketingTests() {
  const [phase, setPhase] = useState<Phase>("picker");
  const [activeExam, setActiveExam] = useState<Exam | null>(null);
  const [shuffled, setShuffled] = useState<Question[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number | number[]>>({});
  const [candidate, setCandidate] = useState<Candidate>({ name: "", email: "" });
  const [result, setResult] = useState<ExamResult | null>(null);
  const [history, setHistory] = useState<ExamResult[]>([]);
  const [viewingHistory, setViewingHistory] = useState<ExamResult | null>(null);
  const [startTime, setStartTime] = useState(0);
  const [secondsLeft, setSecondsLeft] = useState(0);
  const [timedOut, setTimedOut] = useState(false);
  const [tabSwitches, setTabSwitches] = useState(0);

  // Refs that mirror the latest state so the timer's auto-submit closure
  // never reads stale answers/history (the interval effect only re-runs on
  // phase/exam change, so it would otherwise capture the initial empty state).
  const answersRef = useRef(answers);
  const shuffledRef = useRef(shuffled);
  const candidateRef = useRef(candidate);
  const startTimeRef = useRef(startTime);
  const historyRef = useRef(history);
  const activeExamRef = useRef(activeExam);
  const tabSwitchesRef = useRef(tabSwitches);
  useEffect(() => { answersRef.current = answers; }, [answers]);
  useEffect(() => { shuffledRef.current = shuffled; }, [shuffled]);
  useEffect(() => { candidateRef.current = candidate; }, [candidate]);
  useEffect(() => { startTimeRef.current = startTime; }, [startTime]);
  useEffect(() => { historyRef.current = history; }, [history]);
  useEffect(() => { activeExamRef.current = activeExam; }, [activeExam]);
  useEffect(() => { tabSwitchesRef.current = tabSwitches; }, [tabSwitches]);

  // hydrate candidate + history on mount
  useEffect(() => {
    setCandidate(loadCandidate());
    setHistory(loadHistory());
  }, []);

  // countdown timer
  const submittedRef = useRef(false);
  useEffect(() => {
    if (phase !== "running" || !activeExam) return;
    submittedRef.current = false;
    const total = activeExam.durationMinutes * 60;
    setSecondsLeft(total);
    const deadline = Date.now() + total * 1000;
    const id = setInterval(() => {
      const left = Math.max(0, Math.round((deadline - Date.now()) / 1000));
      setSecondsLeft(left);
      if (left <= 0 && !submittedRef.current) {
        submittedRef.current = true;
        setTimedOut(true);
        clearInterval(id);
        // auto-submit on expiry — reads latest state via refs
        finishExam(true);
      }
    }, 1000);
    return () => clearInterval(id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [phase, activeExam]);

  // Anti-cheat: tab-switch detection. Active only while running so historical
  // review / picker navigation doesn't inflate the count. Reads/writes the ref
  // directly so the timer's stale-closure auto-submit captures the latest tally.
  useEffect(() => {
    if (phase !== "running") return;
    const increment = () => {
      setTabSwitches((n) => n + 1);
      tabSwitchesRef.current += 1;
    };
    const onVisibility = () => {
      if (document.hidden) increment();
    };
    const onBlur = () => increment();
    document.addEventListener("visibilitychange", onVisibility);
    window.addEventListener("blur", onBlur);
    return () => {
      document.removeEventListener("visibilitychange", onVisibility);
      window.removeEventListener("blur", onBlur);
    };
  }, [phase]);

  const startExam = (exam: Exam) => {
    if (!candidate.name.trim()) return;
    saveCandidate(candidate);
    setActiveExam(exam);
    setShuffled(shuffle(exam.questions));
    setCurrentIdx(0);
    setAnswers({});
    setResult(null);
    setViewingHistory(null);
    setTimedOut(false);
    setTabSwitches(0);
    tabSwitchesRef.current = 0;
    setStartTime(Date.now());
    setPhase("running");
  };

  const selectAnswer = (questionId: string, optionIdx: number) => {
    setAnswers((prev) => ({ ...prev, [questionId]: optionIdx }));
  };

  const toggleMultiAnswer = (questionId: string, optionIdx: number) => {
    setAnswers((prev) => {
      const cur = prev[questionId];
      const arr = Array.isArray(cur) ? cur : [];
      const next = arr.includes(optionIdx)
        ? arr.filter((i) => i !== optionIdx)
        : [...arr, optionIdx];
      const cp = { ...prev };
      if (next.length === 0) delete cp[questionId];
      else cp[questionId] = next;
      return cp;
    });
  };

  const setNumericAnswer = (questionId: string, raw: string) => {
    setAnswers((prev) => {
      const cp = { ...prev };
      if (raw === "" || Number.isNaN(Number(raw))) delete cp[questionId];
      else cp[questionId] = Number(raw);
      return cp;
    });
  };

  const computeResult = (isTimeout: boolean): ExamResult => {
    const exam = activeExamRef.current;
    const qs = shuffledRef.current;
    const ans = answersRef.current;
    const cand = candidateRef.current;
    const start = startTimeRef.current;
    if (!exam) throw new Error("no active exam");
    const breakdown: Record<string, { correct: number; total: number; pct: number }> = {};
    const records: AnswerRecord[] = [];
    let correctCount = 0;
    let earnedWeightSum = 0;
    for (const q of qs) {
      const sel = ans[q.id];
      const maxWeight = DIFFICULTY_WEIGHT[q.difficulty];
      let earnedWeight = 0;
      let isCorrect = false;
      let selectedRec: number | number[];
      let correctRec: number | number[];
      if (isMultiSelect(q)) {
        const selectedNums: number[] = Array.isArray(sel) ? sel : [];
        const correctSet = new Set(q.correct);
        const tp = selectedNums.filter((i) => correctSet.has(i)).length;
        const fp = selectedNums.filter((i) => !correctSet.has(i)).length;
        // Partial credit: (true positives − false positives) / correct count,
        // clamped to [0,1]. Full weight only when all correct and no extras.
        const frac = Math.max(0, Math.min(1, (tp - fp) / q.correct.length));
        earnedWeight = frac * maxWeight;
        isCorrect = frac >= 1;
        selectedRec = selectedNums;
        correctRec = q.correct;
      } else if (isNumeric(q)) {
        const selNum = typeof sel === "number" ? sel : NaN;
        const ok = !Number.isNaN(selNum) && Math.abs(selNum - q.correct) <= q.tolerance;
        earnedWeight = ok ? maxWeight : 0;
        isCorrect = ok;
        selectedRec = selNum;
        correctRec = q.correct;
      } else {
        const selNum = typeof sel === "number" ? sel : -1;
        const ok = selNum === q.correct;
        earnedWeight = ok ? maxWeight : 0;
        isCorrect = ok;
        selectedRec = selNum;
        correctRec = q.correct;
      }
      earnedWeightSum += earnedWeight;
      if (isCorrect) correctCount++;
      records.push({
        questionId: q.id,
        type: q.type,
        selected: selectedRec,
        correct: correctRec,
        skill: q.skill,
        difficulty: q.difficulty,
        isCorrect,
        earnedWeight,
        maxWeight,
      });
      if (!breakdown[q.skill]) breakdown[q.skill] = { correct: 0, total: 0, pct: 0 };
      breakdown[q.skill]!.total += 1;
      if (isCorrect) breakdown[q.skill]!.correct += 1;
    }
    for (const k of Object.keys(breakdown)) {
      const b = breakdown[k]!;
      b.pct = Math.round((b.correct / b.total) * 100);
    }
    const total = qs.length;
    const percentage = Math.round((correctCount / total) * 100);
    const maxWeight = examMaxWeight(exam);
    const weightedPercentage = maxWeight > 0 ? Math.round((earnedWeightSum / maxWeight) * 100) : 0;
    return {
      attemptId: `${exam.id}-${Date.now()}`,
      examId: exam.id,
      examTitle: exam.title,
      domain: exam.domain,
      score: correctCount,
      total,
      correctCount,
      percentage,
      passed: weightedPercentage >= exam.passingScore,
      band: bandFor(weightedPercentage),
      skillBreakdown: breakdown,
      answers: records,
      candidate: cand.name.trim(),
      email: cand.email.trim(),
      elapsedSeconds: Math.round((Date.now() - start) / 1000),
      timedOut: isTimeout,
      tabSwitches: tabSwitchesRef.current,
      takenAt: Date.now(),
    };
  };

  const finishExam = (isTimeout: boolean) => {
    submittedRef.current = true;
    const r = computeResult(isTimeout);
    setResult(r);
    const next = [r, ...historyRef.current].slice(0, 100);
    setHistory(next);
    saveHistory(next);
    setPhase("results");
  };

  const submitExam = () => finishExam(false);

  const restart = () => {
    setPhase("picker");
    setActiveExam(null);
    setShuffled([]);
    setAnswers({});
    setResult(null);
    setViewingHistory(null);
    setTimedOut(false);
    setTabSwitches(0);
    tabSwitchesRef.current = 0;
  };

  const clearHistory = () => {
    setHistory([]);
    saveHistory([]);
  };

  const viewHistoryItem = (item: ExamResult) => {
    setViewingHistory(item);
    setPhase("results");
  };

  const answeredCount = Object.keys(answers).length;
  const allAnswered = activeExam ? answeredCount >= shuffled.length : false;

  if (phase === "picker") {
    return (
      <ExamPicker
        onPick={startExam}
        candidate={candidate}
        setCandidate={setCandidate}
        history={history}
        onViewHistory={(item) => viewHistoryItem(item)}
        onShowHistory={() => setPhase("history")}
        onShowCompare={() => setPhase("compare")}
        onClearHistory={clearHistory}
      />
    );
  }

  if (phase === "history") {
    return (
      <HistoryView
        history={history}
        onView={(item) => viewHistoryItem(item)}
        onBack={() => setPhase("picker")}
        onClear={clearHistory}
      />
    );
  }

  if (phase === "compare") {
    return (
      <RecruiterCompare
        history={history}
        onBack={() => setPhase("picker")}
        onViewAttempt={(a) => {
          setViewingHistory(a);
          setPhase("results");
        }}
      />
    );
  }

  if (phase === "results") {
    const r = viewingHistory ?? result;
    if (r) {
      return (
        <ResultView
          result={r}
          exam={getExam(r.examId)}
          onRestart={restart}
          isHistorical={!!viewingHistory}
        />
      );
    }
  }

  if (!activeExam) return null;
  const q = shuffled[currentIdx]!;
  const rawSelected = answers[q.id];
  const progress = Math.round((answeredCount / shuffled.length) * 100);
  const lowTime = secondsLeft <= 60;
  const totalSeconds = activeExam.durationMinutes * 60;

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="flex items-center gap-2">
              <h2 className="text-xl font-bold text-gray-900">{activeExam.title}</h2>
              <Badge variant="secondary">{activeExam.level}</Badge>
            </div>
            <p className="text-sm text-gray-500 mt-1">
              Question {currentIdx + 1} of {shuffled.length} · {answeredCount}/{shuffled.length} answered
              {timedOut && <span className="text-red-600 font-medium"> · Time expired — auto-submitted</span>}
            </p>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-center">
              <div className="text-xs text-gray-500">Time left</div>
              <div
                className={`text-lg font-bold tabular-nums ${lowTime ? "text-red-600" : "text-gray-900"}`}
              >
                {fmtCountdown(secondsLeft)}
              </div>
            </div>
            <div className="text-center">
              <div className="text-xs text-gray-500">Pass mark</div>
              <div className="text-lg font-bold text-gray-900">{activeExam.passingScore}%</div>
            </div>
            <div className="text-center">
              <div className="text-xs text-gray-500">Tab switches</div>
              <div
                className={`text-lg font-bold tabular-nums ${
                  tabSwitches >= 3 ? "text-red-600" : tabSwitches > 0 ? "text-amber-600" : "text-gray-900"
                }`}
              >
                {tabSwitches}
              </div>
            </div>
          </div>
        </div>
        <div className="mt-4 h-2 bg-gray-100 rounded-full overflow-hidden">
          <div
            className="h-full bg-indigo-600 transition-all"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="mt-2 h-1 bg-gray-100 rounded-full overflow-hidden">
          <div
            className={`h-full transition-all ${lowTime ? "bg-red-500" : "bg-gray-400"}`}
            style={{ width: `${(secondsLeft / totalSeconds) * 100}%` }}
          />
        </div>
      </Card>

      {tabSwitches >= 3 && (
        <div className="rounded-lg border border-amber-300 bg-amber-50 text-amber-800 px-4 py-3 text-sm font-medium">
          Repeated tab switching detected — this is recorded on your report.
        </div>
      )}

      <Card className="p-6">
        <div className="mb-3 flex items-center gap-2">
          <Badge variant="outline">{activeExam.domain}</Badge>
          <Badge variant="secondary">Skill: {q.skill}</Badge>
          <Badge variant="outline">{difficultyLabel(q.difficulty)}</Badge>
          <Badge variant="outline">{q.type}</Badge>
        </div>
        <p className="text-lg font-semibold text-gray-900 mb-4">{q.prompt}</p>
        <div className="space-y-2">
          {isNumeric(q) ? (
            <div className="flex items-center gap-2">
              <Input
                type="number"
                step="any"
                value={typeof rawSelected === "number" ? String(rawSelected) : ""}
                onChange={(e) => setNumericAnswer(q.id, e.target.value)}
                disabled={timedOut}
                className="max-w-xs"
                aria-label="Numeric answer"
              />
              {q.unit && <span className="text-sm text-gray-600">{q.unit}</span>}
            </div>
          ) : isMultiSelect(q) ? (
            q.options.map((opt, idx) => {
              const checked = Array.isArray(rawSelected) && rawSelected.includes(idx);
              return (
                <button
                  key={idx}
                  onClick={() => toggleMultiAnswer(q.id, idx)}
                  disabled={timedOut}
                  className={`w-full text-left p-3 rounded-lg border flex items-center gap-3 transition-colors ${
                    checked
                      ? "border-indigo-500 bg-indigo-50"
                      : "border-gray-200 hover:border-indigo-300 hover:bg-gray-50"
                  } ${timedOut ? "opacity-60 cursor-not-allowed" : ""}`}
                >
                  <span
                    className={`w-5 h-5 rounded border flex items-center justify-center text-xs flex-shrink-0 ${
                      checked ? "bg-indigo-600 border-indigo-600 text-white" : "border-gray-300"
                    }`}
                  >
                    {checked ? "✓" : ""}
                  </span>
                  <span className="font-medium mr-1 text-indigo-600">
                    {String.fromCharCode(65 + idx)}.
                  </span>
                  <span className="text-sm text-gray-800">{opt}</span>
                </button>
              );
            })
          ) : (
            q.options.map((opt, idx) => {
              const active = typeof rawSelected === "number" && rawSelected === idx;
              return (
                <button
                  key={idx}
                  onClick={() => selectAnswer(q.id, idx)}
                  disabled={timedOut}
                  className={`w-full text-left p-3 rounded-lg border transition-colors ${
                    active
                      ? "border-indigo-500 bg-indigo-50"
                      : "border-gray-200 hover:border-indigo-300 hover:bg-gray-50"
                  } ${timedOut ? "opacity-60 cursor-not-allowed" : ""}`}
                >
                  <span className="font-medium mr-2 text-indigo-600">
                    {String.fromCharCode(65 + idx)}.
                  </span>
                  <span className="text-sm text-gray-800">{opt}</span>
                </button>
              );
            })
          )}
        </div>
      </Card>

      <div className="flex items-center justify-between flex-wrap gap-3">
        <Button
          variant="outline"
          onClick={() => setCurrentIdx((i) => Math.max(0, i - 1))}
          disabled={currentIdx === 0 || timedOut}
        >
          Previous
        </Button>
        <div className="flex gap-1 flex-wrap max-w-full">
          {shuffled.map((sq, idx) => {
            const answered = answers[sq.id] !== undefined;
            const isCurrent = idx === currentIdx;
            return (
              <button
                key={sq.id}
                onClick={() => setCurrentIdx(idx)}
                disabled={timedOut}
                className={`w-8 h-8 rounded-md text-xs font-medium transition-colors ${
                  isCurrent
                    ? "bg-indigo-600 text-white"
                    : answered
                      ? "bg-indigo-100 text-indigo-700"
                      : "bg-gray-100 text-gray-500 hover:bg-gray-200"
                } ${timedOut ? "cursor-not-allowed" : ""}`}
                aria-label={`Go to question ${idx + 1}`}
              >
                {idx + 1}
              </button>
            );
          })}
        </div>
        {currentIdx < shuffled.length - 1 ? (
          <Button
            onClick={() => setCurrentIdx((i) => Math.min(shuffled.length - 1, i + 1))}
            disabled={timedOut}
          >
            Next
          </Button>
        ) : (
          <Button onClick={submitExam} disabled={!allAnswered || timedOut}>
            {allAnswered ? "Submit Exam" : `Answer all (${answeredCount}/${shuffled.length})`}
          </Button>
        )}
      </div>
    </div>
  );
}

function ExamPicker({
  onPick,
  candidate,
  setCandidate,
  history,
  onViewHistory,
  onShowHistory,
  onShowCompare,
  onClearHistory,
}: {
  onPick: (e: Exam) => void;
  candidate: Candidate;
  setCandidate: (c: Candidate) => void;
  history: ExamResult[];
  onViewHistory: (item: ExamResult) => void;
  onShowHistory: () => void;
  onShowCompare: () => void;
  onClearHistory: () => void;
}) {
  const canStart = candidate.name.trim().length > 0;
  return (
    <div className="space-y-6">
      <Card className="p-6">
        <h2 className="text-xl font-bold text-gray-900">Marketing Professional Exams</h2>
        <p className="text-sm text-gray-600 mt-1">
          Recruiting-grade assessments across marketing disciplines. Each exam is timed,
          skill-tagged, and scored against professional benchmarks with per-skill breakdowns
          for hiring decisions.
        </p>
        <div className="mt-4 grid grid-cols-2 sm:grid-cols-4 gap-3 text-center">
          <Stat label="Exams" value={EXAMS.length} />
          <Stat label="Questions" value={EXAMS.reduce((n, e) => n + e.questions.length, 0)} />
          <Stat label="Domains" value={new Set(EXAMS.map((e) => e.domain)).size} />
          <Stat label="Attempts" value={history.length} />
        </div>
      </Card>

      <Card className="p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-1">Candidate Identity</h3>
        <p className="text-sm text-gray-500 mb-4">
          Enter the candidate's name before starting. This is recorded on the report and
          remembered for this browser.
        </p>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div>
            <label className="block text-xs font-medium text-gray-700 mb-1">Name *</label>
            <Input
              value={candidate.name}
              onChange={(e) => setCandidate({ ...candidate, name: e.target.value })}
              placeholder="e.g. Jordan Rivera"
              invalid={false}
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-700 mb-1">Email (optional)</label>
            <Input
              value={candidate.email}
              onChange={(e) => setCandidate({ ...candidate, email: e.target.value })}
              placeholder="candidate@company.com"
              type="email"
            />
          </div>
        </div>
        {!canStart && (
          <p className="text-xs text-amber-600 mt-2">A name is required to start an exam.</p>
        )}
      </Card>

      {history.length > 0 && (
        <Card className="p-5">
          <div className="flex items-center justify-between mb-3">
            <h3 className="text-sm font-semibold text-gray-900">Recent Attempts</h3>
            <div className="flex gap-2">
              <Button variant="ghost" onClick={onShowHistory}>History</Button>
              <Button variant="ghost" onClick={onShowCompare}>Recruiter Compare</Button>
              <Button variant="ghost" onClick={onClearHistory}>Clear</Button>
            </div>
          </div>
          <div className="space-y-2">
            {history.slice(0, 3).map((h) => (
              <button
                key={h.attemptId}
                onClick={() => onViewHistory(h)}
                className="w-full flex items-center justify-between text-left p-3 rounded-lg border border-gray-200 hover:border-indigo-300 hover:bg-gray-50 transition-colors"
              >
                <div>
                  <div className="text-sm font-medium text-gray-900">{h.candidate} · {h.examTitle}</div>
                  <div className="text-xs text-gray-500">
                    {new Date(h.takenAt).toLocaleString()} · {fmtDuration(h.elapsedSeconds)}
                    {h.timedOut && " · timed out"}
                    {h.tabSwitches > 0 && ` · ${h.tabSwitches} tab switches`}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <span className={`text-sm font-bold ${h.passed ? "text-green-600" : "text-red-600"}`}>
                    {h.percentage}%
                  </span>
                  <Badge variant={h.passed ? "default" : "destructive"}>{h.band.band}</Badge>
                </div>
              </button>
            ))}
          </div>
        </Card>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {EXAMS.map((exam) => (
          <Card key={exam.id} className="p-5 flex flex-col">
            <div className="flex items-center justify-between mb-2">
              <Badge variant="secondary">{exam.domain}</Badge>
              <Badge variant="outline">{exam.level}</Badge>
            </div>
            <h3 className="text-lg font-bold text-gray-900">{exam.title}</h3>
            <p className="text-sm text-gray-600 mt-2 flex-1">{exam.description}</p>
            <div className="mt-4 grid grid-cols-3 gap-2 text-center text-xs">
              <MiniStat label="Questions" value={exam.questions.length} />
              <MiniStat label="Minutes" value={exam.durationMinutes} />
              <MiniStat label="Pass" value={`${exam.passingScore}%`} />
            </div>
            <Button className="mt-4 w-full" onClick={() => onPick(exam)} disabled={!canStart}>
              {canStart ? "Start Exam" : "Enter name to start"}
            </Button>
          </Card>
        ))}
      </div>
    </div>
  );
}

function HistoryView({
  history,
  onView,
  onBack,
  onClear,
}: {
  history: ExamResult[];
  onView: (item: ExamResult) => void;
  onBack: () => void;
  onClear: () => void;
}) {
  return (
    <div className="space-y-6">
      <Card className="p-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h2 className="text-xl font-bold text-gray-900">Exam History</h2>
            <p className="text-sm text-gray-500 mt-1">
              {history.length} attempt{history.length === 1 ? "" : "s"} stored locally in this browser.
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" onClick={onBack}>Back to exams</Button>
            {history.length > 0 && <Button variant="ghost" onClick={onClear}>Clear all</Button>}
          </div>
        </div>
      </Card>

      {history.length === 0 ? (
        <Card className="p-10 text-center">
          <p className="text-gray-500">No attempts yet. Complete an exam to see it here.</p>
        </Card>
      ) : (
        <Card className="p-2">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs uppercase tracking-wider text-gray-500 border-b">
                  <th className="p-3">Candidate</th>
                  <th className="p-3">Exam</th>
                  <th className="p-3">Date</th>
                  <th className="p-3">Duration</th>
                  <th className="p-3">Score</th>
                  <th className="p-3">Band</th>
                  <th className="p-3">Tabs</th>
                  <th className="p-3">Result</th>
                  <th className="p-3"></th>
                </tr>
              </thead>
              <tbody>
                {history.map((h) => (
                  <tr key={h.attemptId} className="border-b last:border-0 hover:bg-gray-50">
                    <td className="p-3 font-medium text-gray-900">{h.candidate}</td>
                    <td className="p-3 text-gray-700">{h.examTitle}</td>
                    <td className="p-3 text-gray-500">{new Date(h.takenAt).toLocaleString()}</td>
                    <td className="p-3 text-gray-500">
                      {fmtDuration(h.elapsedSeconds)}{h.timedOut && " ⏱"}
                    </td>
                    <td className="p-3 font-semibold text-gray-900">{h.percentage}%</td>
                    <td className="p-3">
                      <span className={`inline-flex px-2 py-0.5 rounded-full text-xs font-medium border ${gradeColor(h.percentage)}`}>
                        {h.band.band}
                      </span>
                    </td>
                    <td className="p-3">
                      <span className={`text-xs font-medium ${h.tabSwitches >= 3 ? "text-red-600" : h.tabSwitches > 0 ? "text-amber-600" : "text-gray-400"}`}>
                        {h.tabSwitches}
                      </span>
                    </td>
                    <td className="p-3">
                      <span className={`font-medium ${h.passed ? "text-green-600" : "text-red-600"}`}>
                        {h.passed ? "PASS" : "FAIL"}
                      </span>
                    </td>
                    <td className="p-3">
                      <Button variant="ghost" onClick={() => onView(h)}>View</Button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Card>
      )}
    </div>
  );
}

function ResultView({
  result,
  exam,
  onRestart,
  isHistorical,
}: {
  result: ExamResult;
  exam?: Exam;
  onRestart: () => void;
  isHistorical: boolean;
}) {
  const answerRecords = result.answers as AnswerRecord[];
  const skills = useMemo(
    () =>
      Object.entries(result.skillBreakdown).sort((a, b) => b[1].pct - a[1].pct),
    [result],
  );
  const weightedPct = useMemo(() => {
    const earned = answerRecords.reduce((s, r) => s + r.earnedWeight, 0);
    const max = answerRecords.reduce((s, r) => s + r.maxWeight, 0);
    return max > 0 ? Math.round((earned / max) * 100) : 0;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [result]);

  return (
    <div className="space-y-6">
      <ExamCertificate result={result} />

      <Card className="p-6">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <div className="text-xs uppercase tracking-wider text-gray-500">
              {isHistorical ? "Historical Report" : "Recruiting Report"} · {result.domain}
            </div>
            <h2 className="text-xl font-bold text-gray-900">{result.examTitle}</h2>
            <p className="text-sm text-gray-600 mt-1">
              Candidate: <span className="font-medium">{result.candidate}</span>
              {result.email && <> · {result.email}</>}
              <br />
              Date: {new Date(result.takenAt).toLocaleString()} ·
              Duration: {fmtDuration(result.elapsedSeconds)}
              {result.timedOut && <span className="text-red-600 font-medium"> · Timed out (auto-submitted)</span>}
              {result.tabSwitches > 0 && (
                <span className={`font-medium ${result.tabSwitches >= 3 ? "text-red-600" : "text-amber-600"}`}>
                  {" · "}Tab switches: {result.tabSwitches}
                </span>
              )}
            </p>
          </div>
          <div className="text-center">
            <div
              className={`inline-flex items-center justify-center w-20 h-20 rounded-full border-4 text-2xl font-bold ${gradeColor(
                weightedPct,
              )}`}
            >
              {result.band.band}
            </div>
            <div className="text-xs text-gray-500 mt-1">{result.band.label}</div>
          </div>
        </div>

        <div className="mt-5 grid grid-cols-2 sm:grid-cols-4 gap-3 text-center">
          <BigStat label="Score" value={`${result.correctCount}/${result.total}`} />
          <BigStat label="Raw %" value={`${result.percentage}%`} />
          <BigStat label="Weighted %" value={`${weightedPct}%`} />
          <BigStat
            label="Result"
            value={result.passed ? "PASS" : "FAIL"}
            highlight={result.passed ? "text-green-600" : "text-red-600"}
          />
        </div>
        <div className="mt-2 text-center text-xs text-gray-500">
          Pass mark: {exam?.passingScore ?? 70}% (weighted) · Tab switches: {result.tabSwitches}
        </div>

        <div className="mt-4">
          <div className={`inline-flex px-3 py-1 rounded-full text-sm font-medium border ${gradeColor(weightedPct)}`}>
            {result.passed
              ? weightedPct >= 85
                ? "Recruiter signal: Strong hire — clear command of the discipline."
                : "Recruiter signal: Pass — competent practitioner, probe weaker skills."
              : "Recruiter signal: Below threshold — revisit fundamentals before re-screen."}
          </div>
        </div>
      </Card>

      <Card className="p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Skill Breakdown</h3>
        <div className="space-y-3">
          {skills.map(([skill, data]) => (
            <div key={skill}>
              <div className="flex items-center justify-between text-sm mb-1">
                <span className="font-medium text-gray-700 capitalize">{skill.replace(/-/g, " ")}</span>
                <span className="text-gray-500">
                  {data.correct}/{data.total} · {data.pct}%
                </span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                <div
                  className={`h-full transition-all ${
                    data.pct >= 80 ? "bg-green-500" : data.pct >= 60 ? "bg-indigo-500" : "bg-amber-500"
                  }`}
                  style={{ width: `${data.pct}%` }}
                />
              </div>
            </div>
          ))}
        </div>
      </Card>

      {exam && (
        <Card className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Answer Review</h3>
          <div className="space-y-4">
            {exam.questions.map((q, idx) => {
              const rec = answerRecords.find((r) => r.questionId === q.id);
              return (
                <div key={q.id} className="border border-gray-200 rounded-lg p-4">
                  <div className="flex items-start gap-2">
                    <span
                      className={`mt-0.5 inline-flex items-center justify-center w-6 h-6 rounded-full text-xs font-bold flex-shrink-0 ${
                        rec?.isCorrect ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"
                      }`}
                    >
                      {rec?.isCorrect ? "✓" : "✗"}
                    </span>
                    <div className="flex-1">
                      <p className="text-sm font-medium text-gray-900">
                        {idx + 1}. {q.prompt}
                      </p>
                      <div className="mt-2 space-y-1 text-sm">
                        {isNumeric(q) ? (
                          <>
                            <div className="text-gray-700">
                              Your answer:{" "}
                              <span className="font-medium">
                                {rec && typeof rec.selected === "number" && !Number.isNaN(rec.selected)
                                  ? rec.selected
                                  : "—"}
                                {q.unit ? ` ${q.unit}` : ""}
                              </span>
                            </div>
                            <div className="text-green-800">
                              Correct: <span className="font-medium">{q.correct} ± {q.tolerance}{q.unit ? ` ${q.unit}` : ""}</span>
                            </div>
                          </>
                        ) : isMultiSelect(q) ? (
                          q.options.map((opt, oIdx) => {
                            const correctSet = new Set(q.correct);
                            const isCorrectOpt = correctSet.has(oIdx);
                            const selArr =
                              rec && Array.isArray(rec.selected) ? rec.selected : [];
                            const isSelected = selArr.includes(oIdx);
                            return (
                              <div
                                key={oIdx}
                                className={`px-2 py-1 rounded flex items-center gap-2 ${
                                  isCorrectOpt
                                    ? "bg-green-50 text-green-800"
                                    : isSelected
                                      ? "bg-red-50 text-red-800"
                                      : "text-gray-600"
                                }`}
                              >
                                <span className="font-mono text-xs">
                                  [{isSelected ? "x" : " "}]
                                </span>
                                <span className="font-medium mr-1">
                                  {String.fromCharCode(65 + oIdx)}.
                                </span>
                                {opt}
                                {isCorrectOpt && " (correct)"}
                                {isSelected && !isCorrectOpt && " (your answer)"}
                                {!isCorrectOpt && !isSelected && selArr.length === 0 && " (not answered)"}
                              </div>
                            );
                          })
                        ) : (
                          q.options.map((opt, oIdx) => {
                            const isCorrectOpt = oIdx === q.correct;
                            const selNum =
                              rec && typeof rec.selected === "number" ? rec.selected : -1;
                            const isSelected = oIdx === selNum;
                            return (
                              <div
                                key={oIdx}
                                className={`px-2 py-1 rounded ${
                                  isCorrectOpt
                                    ? "bg-green-50 text-green-800"
                                    : isSelected
                                      ? "bg-red-50 text-red-800"
                                      : "text-gray-600"
                                }`}
                              >
                                <span className="font-medium mr-1">
                                  {String.fromCharCode(65 + oIdx)}.
                                </span>
                                {opt}
                                {isCorrectOpt && " (correct)"}
                                {isSelected && !isCorrectOpt && " (your answer)"}
                                {!isCorrectOpt && !isSelected && selNum === -1 && " (not answered)"}
                              </div>
                            );
                          })
                        )}
                      </div>
                      <p className="mt-2 text-xs text-gray-500 italic">{q.explanation}</p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </Card>
      )}

      <div className="flex gap-3 flex-wrap">
        <Button onClick={onRestart}>Take Another Exam</Button>
        <Button variant="outline" onClick={() => window.print()}>
          Print / Save PDF Report
        </Button>
      </div>
    </div>
  );
}

function Stat({ label, value }: { label: string; value: number | string }) {
  return (
    <div className="bg-gray-50 rounded-lg p-3">
      <div className="text-2xl font-bold text-gray-900">{value}</div>
      <div className="text-xs text-gray-500">{label}</div>
    </div>
  );
}

function MiniStat({ label, value }: { label: string; value: number | string }) {
  return (
    <div className="bg-gray-50 rounded-md p-2">
      <div className="text-sm font-bold text-gray-900">{value}</div>
      <div className="text-[10px] text-gray-500">{label}</div>
    </div>
  );
}

function BigStat({
  label,
  value,
  highlight,
}: {
  label: string;
  value: string;
  highlight?: string;
}) {
  return (
    <div className="bg-gray-50 rounded-lg p-3">
      <div className={`text-xl font-bold ${highlight ?? "text-gray-900"}`}>{value}</div>
      <div className="text-xs text-gray-500">{label}</div>
    </div>
  );
}

